const catalog = [
    { code: 'SM', address: 'SM10', value: true, note: 'bit decimal' },
    { code: 'SD', address: 'SD10', value: 1, note: 'word decimal' },
    { code: 'X', address: 'X10', value: true, note: 'bit hexadecimal' },
    { code: 'Y', address: 'Y10', value: true, note: 'bit hexadecimal' },
    { code: 'M', address: 'M10', value: true, note: 'bit decimal' },
