const matrixPlcFamily = 'connection';
const activeCatalog = catalog;
const skippedCatalog = [];

const total = activeCatalog.length;
const readKey = 'slmpDeviceMatrixReadIndex';
const writeKey = 'slmpDeviceMatrixWriteIndex';
const resultsKey = 'slmpDeviceMatrixResults';
const pendingKey = 'slmpDeviceMatrixPendingById';
const sessionKey = 'slmpDeviceMatrixSessionId';
const logPathKey = 'slmpDeviceMatrixLogPath';
const timeoutKey = 'slmpDeviceMatrixTimeoutMs';
const totalKey = 'slmpDeviceMatrixTotalCatalog';
const autoModeKey = 'slmpDeviceMatrixAutoMode';
const autoRemainingKey = 'slmpDeviceMatrixAutoRemaining';
const action = String(msg.mode || 'catalog');

flow.set(totalKey, total);
flow.set('slmpDeviceMatrixCatalog', activeCatalog);
flow.set('slmpDeviceMatrixSkippedCatalog', skippedCatalog);
if (!flow.get(timeoutKey)) {
    flow.set(timeoutKey, 5000);
}

function makeSessionId() {
    return new Date().toISOString().replace(/[:.]/g, '-');
}

function ensureSessionId(reset) {
    let sessionId = flow.get(sessionKey);
    if (reset || !sessionId) {
        sessionId = makeSessionId();
        flow.set(sessionKey, sessionId);
    }
    return sessionId;
}

function ensureLogPath(sessionId, reset) {
    let logPath = flow.get(logPathKey);
    if (reset || !logPath) {
        logPath = 'logs/slmp-device-matrix-' + sessionId + '.jsonl';
        flow.set(logPathKey, logPath);
    }
    return logPath;
}

function getPendingMap() {
    return Object.assign({}, flow.get(pendingKey) || {});
}

function getResults() {
    return Array.from(flow.get(resultsKey) || []);
}

function buildSummary() {
    const results = getResults();
    const pending = getPendingMap();
    const summary = {
        kind: 'summary',
        sessionId: ensureSessionId(false),
        logPath: ensureLogPath(ensureSessionId(false), false),
        totalCatalog: total,
        rawCatalog: catalog.length,
        skippedCatalog: skippedCatalog.length,
        plcFamily: matrixPlcFamily,
        autoMode: flow.get(autoModeKey) || null,
        autoRemaining: Number(flow.get(autoRemainingKey) || 0),
        completed: results.length,
        ok: 0,
        skipped: 0,
        ng: 0,
        mismatch: 0,
        timeout: 0,
        pending: Object.keys(pending).length,
        pendingIds: Object.keys(pending)
    };
    for (const entry of results) {
        if (entry.status === 'OK') {
            summary.ok += 1;
        } else if (entry.status === 'SKIPPED') {
            summary.skipped += 1;
        } else {
            summary.ng += 1;
            if (entry.status === 'MISMATCH') {
                summary.mismatch += 1;
            }
            if (entry.status === 'TIMEOUT') {
                summary.timeout += 1;
            }
        }
    }
    return summary;
}

function startAutoRun(mode) {
    flow.set(autoModeKey, mode);
    flow.set(autoRemainingKey, total);
}

function takeAutoSlot(mode) {
    if (flow.get(autoModeKey) !== mode) {
        return;
    }
    const remaining = Number(flow.get(autoRemainingKey) || 0);
    flow.set(autoRemainingKey, Math.max(remaining - 1, 0));
}

function blockWhenPending(actionName) {
    const pending = getPendingMap();
    const pendingIds = Object.keys(pending);
    if (pendingIds.length === 0) {
        return null;
    }
    return [null, null, {
        payload: {
            kind: 'busy',
            status: 'WAITING_FOR_PENDING',
            requestedAction: actionName,
            pending: pendingIds.length,
            pendingIds: pendingIds,
            summary: buildSummary(),
            note: 'Wait for the current read/write result or timeout before sending the next sample.'
        }
    }];
}

function registerPending(kind, index, entry) {
    const sessionId = ensureSessionId(false);
    const logPath = ensureLogPath(sessionId, false);
    const now = new Date().toISOString();
    const requestId = kind + '-' + entry.code + '-' + String(index + 1) + '-' + String(Date.now());
    const pending = getPendingMap();
    const record = {
        kind: 'result',
        plcFamily: matrixPlcFamily,
        requestId: requestId,
        sessionId: sessionId,
        logPath: logPath,
        operation: kind,
        action: kind === 'write' ? 'write-readback' : 'read',
        deviceCode: entry.code,
        address: entry.address,
        target: entry.target || null,
        note: entry.note,
        sequence: {
            index: index + 1,
            total: total
        },
        status: 'PENDING',
        phase: kind === 'write' ? 'WRITE_PENDING' : 'READ_PENDING',
        ok: null,
        expectedValue: kind === 'write' ? entry.value : null,
        writeValue: kind === 'write' ? entry.value : null,
        writeStatus: kind === 'write' ? 'PENDING' : 'SKIPPED',
        readValue: null,
        readStatus: 'PENDING',
        readbackStatus: kind === 'write' ? 'PENDING' : 'SKIPPED',
        error: null,
        startedAt: now,
        updatedAt: now,
        finishedAt: null
    };
    pending[requestId] = record;
    flow.set(pendingKey, pending);
    return record;
}

if (action === 'reset') {
    const sessionId = ensureSessionId(true);
    const logPath = ensureLogPath(sessionId, true);
    flow.set(readKey, 0);
    flow.set(writeKey, 0);
    flow.set(resultsKey, []);
    flow.set(pendingKey, {});
    flow.set(autoModeKey, '');
    flow.set(autoRemainingKey, 0);
    return [null, null, {
        payload: {
            kind: 'reset',
            sessionId: sessionId,
            logPath: logPath,
            totalCatalog: total,
            rawCatalog: catalog.length,
            skippedCatalog: skippedCatalog.length,
            plcFamily: matrixPlcFamily,
            autoMode: flow.get(autoModeKey) || null,
            autoRemaining: Number(flow.get(autoRemainingKey) || 0),
            timeoutMs: flow.get(timeoutKey),
            note: 'In-memory history cleared. Completed results append to the JSONL log file.'
        }
    }];
}

if (action === 'catalog') {
    const sessionId = ensureSessionId(false);
    const logPath = ensureLogPath(sessionId, false);
    return [null, null, {
        payload: {
            kind: 'catalog',
            sessionId: sessionId,
            logPath: logPath,
            totalCatalog: total,
            rawCatalog: catalog.length,
            skippedCatalog: skippedCatalog.length,
            plcFamily: matrixPlcFamily,
            autoMode: flow.get(autoModeKey) || null,
            autoRemaining: Number(flow.get(autoRemainingKey) || 0),
            timeoutMs: flow.get(timeoutKey),
            entries: activeCatalog,
            skippedEntries: skippedCatalog,
            summary: buildSummary()
        }
    }];
}

if (action === 'runAllReads') {
    const busy = blockWhenPending(action);
    if (busy) {
        return busy;
    }
    flow.set(readKey, 0);
    startAutoRun('read');
}

if (action === 'readNext' || action === 'runAllReads') {
    const busy = action === 'runAllReads' ? null : blockWhenPending(action);
    if (busy) {
        return busy;
    }
    const index = Number(flow.get(readKey) || 0) % total;
    const entry = activeCatalog[index];
    flow.set(readKey, index + 1);
    const record = registerPending('read', index, entry);
    takeAutoSlot('read');
    return [
        {
            topic: 'read:' + entry.code,
            action: 'read',
            requestId: record.requestId,
            deviceSample: entry,
            sequence: record.sequence,
            startedAt: record.startedAt,
            addresses: [entry.address],
            target: entry.target || undefined,
            slmpSkipUnsupported: true,
            slmp: { skipUnsupported: true }
        },
        null,
        { payload: record }
    ];
}

if (action === 'runAllWrites') {
    const busy = blockWhenPending(action);
    if (busy) {
        return busy;
    }
    flow.set(writeKey, 0);
    startAutoRun('write');
}

if (action === 'writeNext' || action === 'runAllWrites') {
    const busy = action === 'runAllWrites' ? null : blockWhenPending(action);
    if (busy) {
        return busy;
    }
    const index = Number(flow.get(writeKey) || 0) % total;
    const entry = activeCatalog[index];
    flow.set(writeKey, index + 1);
    const record = registerPending('write', index, entry);
    takeAutoSlot('write');
    const updates = {};
    updates[entry.address] = entry.value;
    return [
        null,
        {
            topic: 'write:' + entry.code,
            action: 'write',
            requestId: record.requestId,
            deviceSample: entry,
            sequence: record.sequence,
            startedAt: record.startedAt,
            payload: updates,
            target: entry.target || undefined,
            slmpSkipUnsupported: true,
            slmp: { skipUnsupported: true }
        },
        { payload: record }
    ];
}

node.error('Unknown mode: ' + action, msg);
return null;

const resultsKey = 'slmpDeviceMatrixResults';
const pendingKey = 'slmpDeviceMatrixPendingById';
const totalKey = 'slmpDeviceMatrixTotalCatalog';
const sessionKey = 'slmpDeviceMatrixSessionId';
