const now = new Date().toISOString();
const address = sample.address || ((msg.slmp && Array.isArray(msg.slmp.addresses) && msg.slmp.addresses[0]) || null);

function valuesMatch(expected, actual) {
    if (typeof expected === 'boolean') {
        if (typeof actual === 'boolean') {
            return expected === actual;
        }
        if (actual === 0 || actual === 1) {
            return Boolean(actual) === expected;
        }
        if (actual === 'true' || actual === 'false') {
            return (actual === 'true') === expected;
        }
    }
    return JSON.stringify(actual) === JSON.stringify(expected);
}

function resolvePlcFamily(message, fallback) {
    return (message.slmp && message.slmp.connection && message.slmp.connection.plcFamily) || fallback || null;
}

function buildAutoNext(record) {
    const autoMode = flow.get(autoModeKey);
    const remaining = Number(flow.get(autoRemainingKey) || 0);
    if (!((autoMode === 'read' && record.operation === 'read') || (autoMode === 'write' && record.operation === 'write'))) {
        return null;
    }
    if (remaining > 0) {
        return { mode: autoMode === 'write' ? 'writeNext' : 'readNext', autoRun: true };
    }
    flow.set(autoModeKey, '');
    flow.set(autoRemainingKey, 0);
    return null;
}

function buildSummary() {
    const summary = {
        kind: 'summary',
        sessionId: flow.get(sessionKey) || null,
        logPath: flow.get(logPathKey) || null,
        totalCatalog: total,
        completed: results.length,
        ok: 0,
        skipped: 0,
        ng: 0,
        mismatch: 0,
        timeout: 0,
        pending: Object.keys(pending).length,
        pendingIds: Object.keys(pending)
    };
    for (const entry of results) {
        if (entry.status === 'OK') {
            summary.ok += 1;
        } else if (entry.status === 'SKIPPED') {
            summary.skipped += 1;
        } else {
            summary.ng += 1;
            if (entry.status === 'MISMATCH') {
                summary.mismatch += 1;
            }
            if (entry.status === 'TIMEOUT') {
                summary.timeout += 1;
            }
        }
    }
    return summary;
}

const record = Object.assign({
    kind: 'result',
    plcFamily: null,
    requestId: msg.requestId || ('read-' + (sample.code || 'unknown') + '-' + String(Date.now())),
    sessionId: flow.get(sessionKey) || null,
    logPath: flow.get(logPathKey) || null,
    operation: msg.action === 'write-readback' ? 'write' : 'read',
    action: msg.action || 'read',
    deviceCode: sample.code || null,
    address: address,
    note: sample.note || '',
    sequence: msg.sequence || null,
    status: 'PENDING',
    phase: 'DONE',
    ok: null,
    expectedValue: null,
    writeValue: null,
    writeStatus: msg.action === 'write-readback' ? 'UNKNOWN' : 'SKIPPED',
    readValue: null,
    readStatus: 'PENDING',
    readbackStatus: msg.action === 'write-readback' ? 'PENDING' : 'SKIPPED',
    error: null,
    startedAt: msg.startedAt || now,
    updatedAt: now,
    finishedAt: now
}, pending[msg.requestId] || {});

record.updatedAt = now;
record.finishedAt = now;
record.phase = 'DONE';
record.address = address;
record.deviceCode = sample.code || record.deviceCode;
record.note = sample.note || record.note || '';
record.plcFamily = resolvePlcFamily(msg, record.plcFamily);
record.sequence = msg.sequence || record.sequence || null;
record.readValue = msg.payload;
record.error = null;

if (msg.action === 'write-readback') {
    const matched = valuesMatch(record.expectedValue, msg.payload);
    record.writeStatus = record.writeStatus === 'OK' ? 'OK' : 'UNKNOWN';
    record.readStatus = matched ? 'OK' : 'MISMATCH';
    record.readbackStatus = matched ? 'OK' : 'MISMATCH';
    record.status = matched ? 'OK' : 'MISMATCH';
    record.ok = matched;
    if (!matched) {
        record.error = 'Readback mismatch';
    }
} else {
    record.writeStatus = 'SKIPPED';
    record.readStatus = 'OK';
    record.readbackStatus = 'SKIPPED';
    record.status = 'OK';
    record.ok = true;
}

if (record.requestId && Object.prototype.hasOwnProperty.call(pending, record.requestId)) {
    delete pending[record.requestId];
}
results.push(record);
flow.set(pendingKey, pending);
flow.set(resultsKey, results);

const autoNext = buildAutoNext(record);
return [
    { payload: record },
    { payload: results },
    { payload: buildSummary() },
    { filename: flow.get(logPathKey), payload: JSON.stringify(record) },
    autoNext
];

