const address = sample.address || updateKeys[0] || null;
const writeKey = address && Object.prototype.hasOwnProperty.call(updates, address) ? address : updateKeys[0];
const writeValue = writeKey && Object.prototype.hasOwnProperty.call(updates, writeKey) ? updates[writeKey] : null;
const record = pending[msg.requestId];

if (record) {
    record.phase = 'READBACK_PENDING';
    record.writeStatus = 'OK';
    record.writeValue = writeValue;
    record.expectedValue = writeValue;
    record.updatedAt = now;
    pending[msg.requestId] = record;
    flow.set(pendingKey, pending);
}

msg.writeRequest = updates;
msg.action = 'write-readback';
msg.addresses = [address || writeKey];
msg.slmpSkipUnsupported = true;
msg.slmp = Object.assign({}, msg.slmp || {}, { skipUnsupported: true });
delete msg.payload;
return msg;

