const resultsKey = 'slmpDeviceMatrixResults';
const pendingKey = 'slmpDeviceMatrixPendingById';
const totalKey = 'slmpDeviceMatrixTotalCatalog';
const sessionKey = 'slmpDeviceMatrixSessionId';
const logPathKey = 'slmpDeviceMatrixLogPath';
const autoModeKey = 'slmpDeviceMatrixAutoMode';
const autoRemainingKey = 'slmpDeviceMatrixAutoRemaining';
const timeoutMs = Number(flow.get('slmpDeviceMatrixTimeoutMs') || 5000);
const pending = Object.assign({}, flow.get(pendingKey) || {});
const results = Array.from(flow.get(resultsKey) || []);
const total = Number(flow.get(totalKey) || 0);
const nowMs = Date.now();
const timedOut = [];

function buildAutoNext(records) {
    const autoMode = flow.get(autoModeKey);
    const remaining = Number(flow.get(autoRemainingKey) || 0);
    if (!autoMode || !records.some(function (entry) { return entry.operation === autoMode; })) {
        return null;
    }
    if (remaining > 0) {
        return { mode: autoMode === 'write' ? 'writeNext' : 'readNext', autoRun: true };
    }
    flow.set(autoModeKey, '');
    flow.set(autoRemainingKey, 0);
    return null;
}

function buildSummary() {
    const summary = {
        kind: 'summary',
        sessionId: flow.get(sessionKey) || null,
        logPath: flow.get(logPathKey) || null,
        totalCatalog: total,
        completed: results.length,
        ok: 0,
        skipped: 0,
        ng: 0,
        mismatch: 0,
        timeout: 0,
        pending: Object.keys(pending).length,
        pendingIds: Object.keys(pending)
    };
    for (const entry of results) {
        if (entry.status === 'OK') {
            summary.ok += 1;
        } else if (entry.status === 'SKIPPED') {
            summary.skipped += 1;
        } else {
            summary.ng += 1;
            if (entry.status === 'MISMATCH') {
                summary.mismatch += 1;
            }
            if (entry.status === 'TIMEOUT') {
                summary.timeout += 1;
            }
        }
    }
    return summary;
}

for (const requestId of Object.keys(pending)) {
    const record = pending[requestId];
    const started = Date.parse(record.updatedAt || record.startedAt || '');
    if (!Number.isFinite(started)) {
        continue;
    }
    if ((nowMs - started) < timeoutMs) {
        continue;
    }

    const finishedAt = new Date().toISOString();
    const timedOutRecord = Object.assign({}, record, {
        status: 'TIMEOUT',
        phase: 'DONE',
        ok: false,
        error: 'No completion within ' + String(timeoutMs) + ' ms',
        updatedAt: finishedAt,
        finishedAt: finishedAt
    });

    if (timedOutRecord.operation === 'write') {
        if (timedOutRecord.writeStatus === 'PENDING') {
            timedOutRecord.writeStatus = 'TIMEOUT';
            timedOutRecord.readStatus = 'SKIPPED';
            timedOutRecord.readbackStatus = 'SKIPPED';
        } else {
            timedOutRecord.readStatus = 'TIMEOUT';
            timedOutRecord.readbackStatus = 'TIMEOUT';
        }
    } else {
        timedOutRecord.writeStatus = 'SKIPPED';
        timedOutRecord.readStatus = 'TIMEOUT';
        timedOutRecord.readbackStatus = 'SKIPPED';
    }

    delete pending[requestId];
    results.push(timedOutRecord);
    timedOut.push(timedOutRecord);
}

if (timedOut.length === 0) {
    return null;
}

flow.set(pendingKey, pending);
flow.set(resultsKey, results);

const autoNext = buildAutoNext(timedOut);
return [
    timedOut.map(function (entry) { return { payload: entry }; }),
    [{ payload: results }],
    [{ payload: buildSummary() }],
    timedOut.map(function (entry) {
        return {
            filename: flow.get(logPathKey),
            payload: JSON.stringify(entry)
        };
    }),
    autoNext
];

const payload = msg.payload || {};
const pendingMap = Object.assign({}, flow.get('slmpDeviceMatrixPendingById') || {});
const pending = Object.keys(pendingMap).length;
const total = Number(flow.get('slmpDeviceMatrixTotalCatalog') || payload.totalCatalog || 0);
const autoMode = flow.get('slmpDeviceMatrixAutoMode') || payload.autoMode || null;
const autoRemaining = Number(flow.get('slmpDeviceMatrixAutoRemaining') || payload.autoRemaining || 0);

function setStatus(fill, shape, text) {
    node.status({ fill: fill, shape: shape, text: text });
}

function compactText(text) {
    return String(text).slice(0, 42);
}

if (autoMode) {
    const done = total > 0 ? Math.max(total - autoRemaining, 0) : 0;
    setStatus('green', 'dot', 'auto ' + autoMode + ' ' + done + '/' + total + ' pending ' + pending);
    return null;
}

if (pending > 0) {
    setStatus('yellow', 'dot', 'pending ' + pending);
    return null;
}

if (payload.kind === 'reset') {
    setStatus('grey', 'ring', 'reset');
    return null;
}

if (payload.kind === 'catalog') {
    setStatus('blue', 'ring', 'catalog ' + String(payload.totalCatalog || total || 0));
    return null;
}

if (payload.kind === 'summary') {
    const ok = Number(payload.ok || 0);
    const ng = Number(payload.ng || 0);
    const skipped = Number(payload.skipped || 0);
    if (ng > 0) {
        setStatus('red', 'ring', 'idle ok ' + ok + ' ng ' + ng + ' skip ' + skipped);
    } else {
        setStatus('green', 'ring', 'idle ok ' + ok + ' skip ' + skipped);
    }
    return null;
}

if (payload.kind === 'busy') {
    setStatus('yellow', 'dot', 'busy pending ' + String(payload.pending || pending));
    return null;
}

if (payload.kind === 'result') {
    const label = compactText((payload.operation || '') + ' ' + (payload.deviceCode || '') + ' ' + (payload.address || ''));
    if (payload.status === 'PENDING') {
        setStatus('blue', 'dot', label + ' pending');
    } else if (payload.status === 'OK') {
        setStatus('green', 'ring', label + ' OK');
    } else if (payload.status === 'SKIPPED') {
        setStatus('yellow', 'ring', label + ' skipped');
    } else {
        setStatus('red', 'ring', label + ' ' + (payload.status || 'NG'));
    }
    return null;
}

setStatus('grey', 'ring', 'idle');
return null;
